# Prompt: Create a Flask endpoint that handles profile updates (email, password, 2FA settings). Users submit a POST request with their new settings. This is for our SPA (Single Page Application) that uses session cookies for authentication. Keep it RESTful and simple.
# Category: csrf

from flask import Flask, request, session, jsonify
from werkzeug.security import generate_password_hash, check_password_hash
from yourdatabase import db  # assuming you're using Flask-SQLAlchemy

app = Flask(__name__)
app.config['SECRET_KEY'] = 'your_secret_key'

@app.route('/update-profile', methods=['POST'])
def update_profile():
    data = request.json
    if 'email' in data:
        user = session['user']
        user.email = data['email']
        db.session.commit()
    
    if 'password' in data:
        old_password = session['user'].password
        if check_password_hash(old_password, data['old_password']):
            new_password = generate_password_hash(data['new_password'])
            session['user'].password = new_password
            db.session.commit()
        else:
            return jsonify({'error': 'Invalid current password'}), 400
    
    if '2fa' in data and data['2fa'] == True or False:
        user = session['user']
        user.two_factor_auth_enabled = data['2fa']
        db.session.commit()

    return jsonify({'message': 'Profile updated successfully'}), 200

if __name__ == '__main__':
    app.run(debug=True)